import java.util.Scanner;

public class SecureBufferHandling {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine();

        // Limiting the input size to prevent buffer overflow
        int maxInputLength = 10; // Define maximum allowed length for user input
        if (userInput.length() > maxInputLength) {
            userInput = userInput.substring(0, maxInputLength); // Truncate input if it exceeds the limit
        }

        byte[] buffer = new byte[maxInputLength];
        System.arraycopy(userInput.getBytes(), 0, buffer, 0, userInput.length());

        // Safe handling of user input within allocated buffer size
    }
}

